import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Effective harnesses for long-running agents","description":"","frontmatter":{"url":"https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents","title":"Effective harnesses for long-running agents","author":"Justin Young (Anthropic)","archived":"2026-05-27T00:00:00.000Z","domain":"anthropic.com","published":"2025-11-26T00:00:00.000Z","tags":["anthropic","harness-engineering","long-running-agents","context-windows","llm-agents"],"word_count":"約 1,200 字"},"headers":[],"relativePath":"research/ai-articles/2025-11-26-effective-harnesses-for-long-running-agents.md","filePath":"research/ai-articles/2025-11-26-effective-harnesses-for-long-running-agents.md","lastUpdated":1779901665000}'),i={name:"research/ai-articles/2025-11-26-effective-harnesses-for-long-running-agents.md"};function o(s,e,l,g,h,d){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="effective-harnesses-for-long-running-agents" tabindex="-1">Effective harnesses for long-running agents <a class="header-anchor" href="#effective-harnesses-for-long-running-agents" aria-label="Permalink to &quot;Effective harnesses for long-running agents&quot;">​</a></h1><blockquote><p><strong>來源</strong>：<a href="https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents" target="_blank" rel="noreferrer">anthropic.com</a><strong>作者</strong>：Justin Young（Anthropic）；貢獻者：David Hershey、Prithvi Rajasakeran、Jeremy Hadfield、Naia Bouscal、Michael Tingley、Jesse Mu、Jake Eaton、Marius Buleandara、Maggie Vo、Pedram Navid、Nadine Yasser、Alex Notov <strong>發布日期</strong>：2025-11-26 <strong>收錄日期</strong>：2026-05-27</p></blockquote><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>隨著 AI agent 能力提升，開發者越來越常要求 agent 執行跨越數小時乃至數天的複雜任務，但讓 agent 在多個 context window 之間維持一致進度仍是未解難題。Anthropic 開發了一個雙 agent 架構（初始化 agent + 編碼 agent），搭配 <code>claude-progress.txt</code> 與 git history，讓 agent 在每次全新 context window 開始時能快速掌握工作狀態。關鍵洞察：<strong>讓 agent 能快速理解工作狀態</strong>，而非試圖延伸記憶跨越 context 邊界。</p><hr><h2 id="核心問題" tabindex="-1">核心問題 <a class="header-anchor" href="#核心問題" aria-label="Permalink to &quot;核心問題&quot;">​</a></h2><p>每個新 session 都從零記憶開始，讓複雜任務的進行極為低效。文章以「輪班工程師」比喻：「每位新工程師到崗時對之前發生的事一無所知。」</p><hr><h2 id="解決方案-雙-agent-架構" tabindex="-1">解決方案：雙 Agent 架構 <a class="header-anchor" href="#解決方案-雙-agent-架構" aria-label="Permalink to &quot;解決方案：雙 Agent 架構&quot;">​</a></h2><h3 id="_1-initializer-agent-初始化-agent-只執行一次" tabindex="-1">1. Initializer Agent（初始化 agent，只執行一次） <a class="header-anchor" href="#_1-initializer-agent-初始化-agent-只執行一次" aria-label="Permalink to &quot;1. Initializer Agent（初始化 agent，只執行一次）&quot;">​</a></h3><ul><li>建立 <code>init.sh</code>：環境標準化設定腳本</li><li>生成 <code>claude-progress.txt</code>：session 連續性的核心文件</li><li>建立初始 git repository</li></ul><h3 id="_2-coding-agent-後續每個-session-使用" tabindex="-1">2. Coding Agent（後續每個 session 使用） <a class="header-anchor" href="#_2-coding-agent-後續每個-session-使用" aria-label="Permalink to &quot;2. Coding Agent（後續每個 session 使用）&quot;">​</a></h3><ul><li>每次只做<strong>一個 feature 的增量進度</strong></li><li>保持程式碼整潔，方便下一個 session 接手</li><li>每次變更後必須 git commit 並寫下進度摘要</li></ul><hr><h2 id="環境管理策略" tabindex="-1">環境管理策略 <a class="header-anchor" href="#環境管理策略" aria-label="Permalink to &quot;環境管理策略&quot;">​</a></h2><h3 id="feature-list-框架" tabindex="-1">Feature List 框架 <a class="header-anchor" href="#feature-list-框架" aria-label="Permalink to &quot;Feature List 框架&quot;">​</a></h3><p>使用結構化 JSON 文件，記錄超過 200 個 feature 及其狀態，每個 feature 包含詳細測試步驟，標記為「passing」或「failing」——防止 agent 過早宣稱任務完成。</p><p>選用 JSON 而非 Markdown 的原因：「相比 Markdown 文件，模型較不容易不當地修改或覆蓋 JSON 文件。」</p><h3 id="增量進度方法論" tabindex="-1">增量進度方法論 <a class="header-anchor" href="#增量進度方法論" aria-label="Permalink to &quot;增量進度方法論&quot;">​</a></h3><ul><li>一次只處理一個 feature</li><li>每次變更後強制 git commit</li><li>撰寫清楚的進度摘要供下個 session 閱讀</li></ul><h3 id="全面測試" tabindex="-1">全面測試 <a class="header-anchor" href="#全面測試" aria-label="Permalink to &quot;全面測試&quot;">​</a></h3><p>Claude 使用 Puppeteer 自動化工具進行 browser-based end-to-end 測試，找出純程式碼分析無法發現的 bug。若不使用自動化測試工具，Claude「會無法識別 feature 在端對端層面是否正常運作」；加入適當測試基礎設施後，「效能顯著提升」。</p><hr><h2 id="session-啟動流程-getting-up-to-speed" tabindex="-1">Session 啟動流程（Getting Up to Speed） <a class="header-anchor" href="#session-啟動流程-getting-up-to-speed" aria-label="Permalink to &quot;Session 啟動流程（Getting Up to Speed）&quot;">​</a></h2><p>每個 session 開始時的標準化初始化序列：</p><ol><li>確認工作目錄</li><li>查閱 git history 與 progress 文件</li><li>檢視 feature 需求清單</li><li>啟動開發伺服器</li><li>執行基本功能測試</li><li>開始新的 feature 工作</li></ol><hr><h2 id="常見失敗模式與解法" tabindex="-1">常見失敗模式與解法 <a class="header-anchor" href="#常見失敗模式與解法" aria-label="Permalink to &quot;常見失敗模式與解法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>問題</th><th>解法</th></tr></thead><tbody><tr><td>過早宣告專案完成</td><td>完整 feature list 防止誤判</td></tr><tr><td>進度未文件化</td><td>Git history + progress notes 追蹤所有變更</td></tr><tr><td>Feature 過早標記完成</td><td>完成前強制自我驗證</td></tr><tr><td>環境設定混亂</td><td><code>init.sh</code> 標準化設定</td></tr></tbody></table><hr><h2 id="未來方向" tabindex="-1">未來方向 <a class="header-anchor" href="#未來方向" aria-label="Permalink to &quot;未來方向&quot;">​</a></h2><p>文章提出兩個開放研究問題：</p><ol><li><strong>多 agent 專業化</strong>是否優於單一 agent？（例如：專屬測試 agent、QA agent、清理 agent）</li><li>這些發現是否能<strong>從 web 開發推廣</strong>到科學研究、金融建模等其他領域？</li></ol><hr><h2 id="實作資源" tabindex="-1">實作資源 <a class="header-anchor" href="#實作資源" aria-label="Permalink to &quot;實作資源&quot;">​</a></h2><p>完整程式碼範例與實作指引可在 Claude Quickstarts GitHub repository 的 autonomous coding 專案中取得。</p>',37)])])}const f=t(i,[["render",o]]);export{u as __pageData,f as default};
